// Configuration: 3 stocks to monitor
const tickers = ['HDFCBANK.NS', 'TCS.NS', 'SUNPHARMA.NS'];
const tickerNames = ['HDFCBANK', 'TCS', 'SUNPHARMA'];
const threshold = 2.0; // Alert if move > 2%

const results = [];

for (let i = 0; i < tickers.length; i++) {
  try {
    // Fetch last 2 days of data from Yahoo Finance
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://query1.finance.yahoo.com/v8/finance/chart/${tickers[i]}`,
      qs: {
        range: '5d',
        interval: '1d'
      },
      headers: {
        'User-Agent': 'Mozilla/5.0'
      }
    });

    const closes = response.chart.result[0].indicators.quote[0].close;
    const validCloses = closes.filter(c => c !== null);

    if (validCloses.length >= 2) {
      const currentClose = validCloses[validCloses.length - 1];
      const previousClose = validCloses[validCloses.length - 2];
      const changePercent = ((currentClose - previousClose) / previousClose) * 100;

      results.push({
        ticker: tickerNames[i],
        currentClose: currentClose.toFixed(2),
        previousClose: previousClose.toFixed(2),
        changePercent: changePercent.toFixed(2),
        triggered: Math.abs(changePercent) > threshold,
        direction: changePercent > 0 ? '📈 UP' : '📉 DOWN',
        timestamp: new Date().toISOString()
      });
    }
  } catch (error) {
    results.push({
      ticker: tickerNames[i],
      error: error.message,
      triggered: false
    });
  }
}

return results.map(r => ({ json: r }));

const items = $input.all();

let alertMessage = '🚨 PRICE ALERT — PortfolioIQ\n\n';
alertMessage += 'The following stocks moved >2% today:\n\n';

for (const item of items) {
  const d = item.json;
  alertMessage += `${d.direction} ${d.ticker}\n`;
  alertMessage += `  Close: ₹${d.currentClose} (prev: ₹${d.previousClose})\n`;
  alertMessage += `  Change: ${d.changePercent}%\n\n`;
}

alertMessage += `\n⏰ Generated: ${new Date().toLocaleString('en-IN', {timeZone: 'Asia/Kolkata'})}`;

return [{ json: { alertMessage, subject: '🚨 PortfolioIQ Price Alert', timestamp: new Date().toISOString() } }];

const items = $input.all();
let summary = 'ℹ️ No stocks moved >2% today.\n\n';

for (const item of items) {
  const d = item.json;
  summary += `${d.ticker}: ${d.changePercent}% (within threshold)\n`;
}

return [{ json: { message: summary } }];
